#include<bits/stdc++.h>
using namespace std;

int main()
{
	int n,a[11],i,j,k;
	scanf("%d",&n);
	for(i=1;i<=n;i++)
	{
		scanf("%d",&a[i]);
	}
	for(i=1;i<=n;i++)
	{
		int flag=0;
		for(j=1;j<=sqrt(a[i]);j++)
		{
			for(k=1;k<=sqrt(a[i]);k++)
			{
				if(j*j+k*k==a[i])
				{
					flag=1;
					printf("Yes\n");
					break;
				}
				else
				{
					flag=0;
				}
			}
			if(flag==1)
			{
				break;
			}
		}
		if(flag==0)
		{
			printf("No\n");
		}
	}
	return 0;
}
